                placeholder="例如：Gig Team"
                autoFocus
                disabled={isCreating}
                maxLength={80}
              />
              {orgError && <p className="text-sm text-destructive">{orgError}</p>}
            </div>
            <DialogFooter>
              <Button
                type="button"
