 * Workflow: 選取 → 上傳到 GCS → 呼叫 parse_document → 監聽 Firestore 狀態
 * Constraints: 僅限本地開發 / staging 驗證；勿在 production 導覽列顯示。
 */

import { useRef, useState, useEffect } from "react";
import {
  FlaskConical,
  FileUp,
  Loader2,
  CheckCircle2,
  XCircle,
  AlertCircle,
  FileText,
  Trash2,
  Code2,
