"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { getDownloadURL, ref, uploadBytes } from "firebase/storage";

import type { WorkspaceEntity } from "@/modules/workspace";
import type { WorkspaceFileListItemDto } from "../../application/dto/file.dto";
import { getWorkspaceFiles } from "../queries/file.queries";
import { resolveFileOrganizationId } from "../../domain/services/resolve-file-organization-id";
import { uploadCompleteFile, uploadInitFile } from "../_actions/file.actions";
import { Badge } from "@ui-shadcn/ui/badge";
import { Button } from "@ui-shadcn/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@ui-shadcn/ui/card";
import { Input } from "@ui-shadcn/ui/input";
import { Label } from "@ui-shadcn/ui/label";
import { getFirebaseStorage } from "@integration-firebase";

interface WorkspaceFilesTabProps {
  readonly workspace: WorkspaceEntity;
}

export function WorkspaceFilesTab({ workspace }: WorkspaceFilesTabProps) {
  const [assets, setAssets] = useState<WorkspaceFileListItemDto[]>([]);
  const [loadState, setLoadState] = useState<"loading" | "loaded" | "error">("loading");
  const [uploadState, setUploadState] = useState<"idle" | "uploading" | "success" | "error">("idle");
  const [uploadMessage, setUploadMessage] = useState<string | null>(null);

  const reloadFiles = useCallback(async () => {
    setLoadState("loading");

    try {
      const nextAssets = await getWorkspaceFiles(workspace);
      setAssets(nextAssets);
      setLoadState("loaded");
    } catch (error) {
      if (process.env.NODE_ENV !== "production") {
        console.warn(
          "[WorkspaceFilesTab] Failed to load file metadata:",
          error instanceof Error ? error.message : "unknown error",
        );
      }

      setAssets([]);
      setLoadState("error");
    }
  }, [workspace]);

  useEffect(() => {
    let cancelled = false;

    async function loadFiles() {
      await reloadFiles();
      if (cancelled) {
        return;
      }
    }

    void loadFiles();

    return () => {
      cancelled = true;
    };
  }, [reloadFiles]);

  async function handleUploadFile(file: File) {
    const organizationId = resolveFileOrganizationId(workspace.accountType, workspace.accountId);
    setUploadState("uploading");
    setUploadMessage(null);

    try {
      const initResult = await uploadInitFile({
        workspaceId: workspace.id,
        organizationId,
        actorAccountId: workspace.accountId,
        fileName: file.name,
        mimeType: file.type || "application/octet-stream",
        sizeBytes: file.size,
      });

      if (!initResult.ok) {
        setUploadState("error");
        setUploadMessage(`Upload initialization failed: ${initResult.error.message}`);
        return;
      }

      const storage = getFirebaseStorage();
      const storageRef = ref(storage, initResult.data.uploadPath);
      await uploadBytes(storageRef, file, {
        contentType: file.type || "application/octet-stream",
      });
      await getDownloadURL(storageRef);

      const completeResult = await uploadCompleteFile({
        workspaceId: workspace.id,
        organizationId,
        actorAccountId: workspace.accountId,
        fileId: initResult.data.fileId,
        versionId: initResult.data.versionId,
      });

      if (!completeResult.ok) {
        setUploadState("error");
        setUploadMessage(`Upload completion failed: ${completeResult.error.message}`);
        return;
      }

      setUploadState("success");
      setUploadMessage(
        `Uploaded ${file.name}; document ${completeResult.data.ragDocumentId} is ${completeResult.data.ragDocumentStatus}.`,
      );

      await reloadFiles();
    } catch (error) {
      if (process.env.NODE_ENV !== "production") {
        console.warn("[WorkspaceFilesTab] Upload flow failed:", error);
      }
      setUploadState("error");
      setUploadMessage(
        error instanceof Error
          ? `Storage upload failed: ${error.message}`
          : "Storage upload failed unexpectedly.",
      );
    }
  }

  const availableCount = useMemo(
    () => assets.filter((asset) => asset.status === "active").length,
    [assets],
  );

  return (
    <Card className="border border-border/50">
      <CardHeader>
        <CardTitle>Files</CardTitle>
        <CardDescription>
          盤點目前已註冊或可立即導出的工作區資產，並提供 upload → storage → firestore 的完整流程入口。
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="rounded-xl border border-border/40 px-4 py-4">
          <div className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
            <div className="space-y-1">
              <Label htmlFor="workspace-file-upload" className="text-sm font-semibold text-foreground">
                Upload file
              </Label>
              <p className="text-xs text-muted-foreground">
                This triggers upload-init, uploads binary to Storage, then writes completion + RAG registration to Firestore.
              </p>
            </div>
            <Input
              id="workspace-file-upload"
              type="file"
              className="max-w-xs"
              disabled={uploadState === "uploading"}
              onChange={(event) => {
                const nextFile = event.target.files?.[0];
                if (!nextFile) {
                  return;
                }

                void handleUploadFile(nextFile);
                event.currentTarget.value = "";
              }}
            />
          </div>
          {uploadMessage && (
            <p
              className={`mt-3 text-xs ${
                uploadState === "error" ? "text-destructive" : "text-emerald-600"
              }`}
            >
              {uploadMessage}
            </p>
          )}
          {uploadState === "uploading" && (
            <p className="mt-3 text-xs text-muted-foreground">Uploading and persisting metadata…</p>
          )}
        </div>

        {loadState === "loading" && (
          <p className="text-sm text-muted-foreground">Loading file metadata…</p>
        )}

        {loadState === "error" && (
          <p className="text-sm text-destructive">
            無法載入已持久化的檔案資料，請稍後再試。
          </p>
        )}

        <div className="grid gap-3 sm:grid-cols-3">
          <div className="rounded-xl border border-border/40 px-4 py-3">
            <p className="text-xs text-muted-foreground">Registered assets</p>
            <p className="mt-1 text-xl font-semibold">{assets.length}</p>
          </div>
          <div className="rounded-xl border border-border/40 px-4 py-3">
            <p className="text-xs text-muted-foreground">Directly available</p>
            <p className="mt-1 text-xl font-semibold">{availableCount}</p>
          </div>
          <div className="rounded-xl border border-border/40 px-4 py-3">
            <p className="text-xs text-muted-foreground">Derived manifests</p>
            <p className="mt-1 text-xl font-semibold">{assets.length - availableCount}</p>
          </div>
        </div>

        <div className="space-y-3">
          {loadState === "loaded" && assets.length === 0 && (
            <div className="rounded-xl border border-dashed border-border/40 px-4 py-6 text-sm text-muted-foreground">
              尚未有持久化的檔案紀錄，後續 upload-init 流程會先在此建立 metadata。
            </div>
          )}

          {assets.map((asset) => (
            <div key={asset.id} className="rounded-xl border border-border/40 px-4 py-4">
              <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
                <div className="space-y-1">
                  <div className="flex flex-wrap items-center gap-2">
                    <p className="text-sm font-semibold text-foreground">{asset.name}</p>
                    <Badge variant={asset.status === "active" ? "secondary" : "outline"}>
                      {asset.status}
                    </Badge>
                    <Badge variant="outline">{asset.kind}</Badge>
                  </div>
                  <p className="text-sm text-muted-foreground">{asset.detail}</p>
                </div>
                <div className="text-xs text-muted-foreground sm:text-right">
                  <p>Source: {asset.source}</p>
                  {asset.href && (
                    <Button asChild variant="link" className="mt-1 inline-flex h-auto p-0 text-xs">
                      <a href={asset.href} target="_blank" rel="noreferrer">
                        Open asset
                      </a>
                    </Button>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

import type { WorkspaceEntity } from "@/modules/workspace";

import { resolveFileOrganizationId } from "../../domain/services/resolve-file-organization-id";
import type { WorkspaceFileListItemDto } from "../../application/dto/file.dto";
import { ListWorkspaceFilesUseCase } from "../../application/use-cases/list-workspace-files.use-case";
import { FirebaseFileRepository } from "../../infrastructure/firebase/FirebaseFileRepository";
import { FirebaseRagDocumentRepository } from "../../infrastructure/firebase/FirebaseRagDocumentRepository";
import type { RagDocumentRecord } from "../../domain/repositories/RagDocumentRepository";

export async function getWorkspaceFiles(workspace: WorkspaceEntity): Promise<WorkspaceFileListItemDto[]> {
  const listWorkspaceFilesUseCase = new ListWorkspaceFilesUseCase(new FirebaseFileRepository());
  const organizationId = resolveFileOrganizationId(workspace.accountType, workspace.accountId);

  return listWorkspaceFilesUseCase.execute({
    workspaceId: workspace.id,
    organizationId,
    actorAccountId: workspace.accountId,
  });
}

export async function getWorkspaceRagDocuments(
  workspace: WorkspaceEntity,
): Promise<readonly RagDocumentRecord[]> {
  const organizationId = resolveFileOrganizationId(workspace.accountType, workspace.accountId);
  const repo = new FirebaseRagDocumentRepository();

  return repo.findByWorkspace({
    organizationId,
    workspaceId: workspace.id,
  });
}

"use client"

import { useEffect, useMemo, useRef, useState } from "react"

import { Button } from "@ui-shadcn/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@ui-shadcn/ui/card"
import { Input } from "@ui-shadcn/ui/input"
import type { NamespaceKind } from "../../domain/entities/namespace.entity"
import { deriveSlugCandidate } from "../../domain/services/slug-policy"
import { ListNamespacesByOrganizationUseCase } from "../../application/use-cases/list-namespaces-by-organization.use-case"
import { RegisterNamespaceUseCase } from "../../application/use-cases/register-namespace.use-case"
import { InMemoryNamespaceRepository } from "../../infrastructure/repositories/in-memory-namespace.repository"

interface NamespacePrototypeViewProps {
  readonly organizationId: string
  readonly ownerAccountId: string
}

interface NamespaceRow {
  id: string
  slug: string
  kind: NamespaceKind
  status: string
}

function createNamespaceId(): string {
  return `ns_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`
}

export function NamespacePrototypeView({ organizationId, ownerAccountId }: NamespacePrototypeViewProps) {
  const repositoryRef = useRef<InMemoryNamespaceRepository | null>(null)
  if (!repositoryRef.current) {
    repositoryRef.current = new InMemoryNamespaceRepository()
  }

  const registerNamespace = useMemo(() => new RegisterNamespaceUseCase(repositoryRef.current!), [])
  const listNamespaces = useMemo(
    () => new ListNamespacesByOrganizationUseCase(repositoryRef.current!),
    [],
  )

  const [displayName, setDisplayName] = useState("")
  const [kind, setKind] = useState<NamespaceKind>("workspace")
  const [rows, setRows] = useState<NamespaceRow[]>([])
  const [errorMessage, setErrorMessage] = useState<string | null>(null)
  const [creating, setCreating] = useState(false)

  async function refreshRows() {
    const list = await listNamespaces.execute({ organizationId })
    const mapped = list
      .map((item) => ({
        id: item.id,
        slug: item.slug.value,
        kind: item.kind,
        status: item.status,
      }))
      .sort((a, b) => a.slug.localeCompare(b.slug, "zh-Hant"))
    setRows(mapped)
  }

  useEffect(() => {
    void refreshRows()
  }, [organizationId])

  async function handleCreateNamespace() {
    const trimmedName = displayName.trim()
    if (!trimmedName) {
      setErrorMessage("請先輸入名稱")
      return
    }

    const slug = deriveSlugCandidate(trimmedName)
    if (!slug) {
      setErrorMessage("名稱無法產生有效 slug，請改用英文或數字")
      return
    }

    setErrorMessage(null)
    setCreating(true)
    try {
      await registerNamespace.execute({
        id: createNamespaceId(),
        slug,
        kind,
        ownerAccountId,
        organizationId,
      })
      setDisplayName("")
      await refreshRows()
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : "建立 namespace 失敗")
    } finally {
      setCreating(false)
    }
  }

  return (
    <div className="space-y-4">
      <Card>
        <CardHeader>
          <CardTitle>Namespace Prototype</CardTitle>
          <CardDescription>
            最小雛型：建立 namespace slug 並以 organization scope 列表檢視，供後續 pages tree 掛載使用。
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          <div className="grid gap-2 md:grid-cols-[minmax(0,1fr)_160px_auto]">
            <Input
              value={displayName}
              onChange={(event) => setDisplayName(event.target.value)}
              placeholder="例如：Product Wiki"
            />
            <select
              value={kind}
              onChange={(event) => setKind(event.target.value as NamespaceKind)}
              className="h-9 rounded-md border border-input bg-background px-3 text-sm"
            >
              <option value="workspace">workspace</option>
              <option value="organization">organization</option>
            </select>
            <Button onClick={() => void handleCreateNamespace()} disabled={creating}>
              {creating ? "建立中..." : "建立 Namespace"}
            </Button>
          </div>

          <div className="rounded-md border border-border/60 bg-muted/20 p-3 text-sm text-muted-foreground">
            slug preview: <span className="font-mono text-foreground">{deriveSlugCandidate(displayName || "sample-namespace") || "-"}</span>
          </div>

          {errorMessage ? (
            <p className="rounded-md border border-destructive/40 bg-destructive/10 px-3 py-2 text-sm text-destructive">
              {errorMessage}
            </p>
          ) : null}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Organization Namespaces</CardTitle>
          <CardDescription>
            organizationId: <span className="font-mono">{organizationId}</span>
          </CardDescription>
        </CardHeader>
        <CardContent>
          {rows.length === 0 ? (
            <p className="text-sm text-muted-foreground">目前尚無 namespace，先建立第一筆。</p>
          ) : (
            <div className="space-y-2">
              {rows.map((row) => (
                <div key={row.id} className="flex flex-wrap items-center justify-between gap-2 rounded-md border border-border/60 p-3">
                  <div className="min-w-0 flex-1">
                    <p className="truncate text-sm font-medium text-foreground">{row.slug}</p>
                    <p className="text-xs text-muted-foreground">id={row.id}</p>
                  </div>
                  <div className="flex items-center gap-2 text-xs">
                    <span className="rounded-full border border-border/60 px-2 py-1">{row.kind}</span>
                    <span className="rounded-full border border-border/60 px-2 py-1">{row.status}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

/**
 * @module workspace-flow/api
 * @file contracts.ts
 * @description Public contracts exposed through the workspace-flow module boundary.
 *
 * All types, DTOs, and projection helpers that external consumers need are
 * re-exported from this single file.  XState internals (canTransition*, nextStatus,
 * isTerminal*) are intentionally NOT exposed here — status machines are internal.
 *
 * @author workspace-flow
 * @created 2026-03-24
 */

// ── Entity types ──────────────────────────────────────────────────────────────

export type { Task } from "../domain/entities/Task";
export type { Issue } from "../domain/entities/Issue";
export type { Invoice } from "../domain/entities/Invoice";
export type { InvoiceItem } from "../domain/entities/InvoiceItem";

// ── Value objects (enum / list only — no transition helpers) ──────────────────

export type { TaskStatus } from "../domain/value-objects/TaskStatus";
export { TASK_STATUSES } from "../domain/value-objects/TaskStatus";

export type { IssueStatus } from "../domain/value-objects/IssueStatus";
export { ISSUE_STATUSES } from "../domain/value-objects/IssueStatus";

export type { IssueStage } from "../domain/value-objects/IssueStage";
export { ISSUE_STAGES } from "../domain/value-objects/IssueStage";

export type { InvoiceStatus } from "../domain/value-objects/InvoiceStatus";
export { INVOICE_STATUSES } from "../domain/value-objects/InvoiceStatus";

// ── Summary projections ───────────────────────────────────────────────────────

export type {
  TaskSummary,
  IssueSummary,
  InvoiceSummary,
  InvoiceItemSummary,
} from "../interfaces/contracts/workspace-flow.contract";

export {
  toTaskSummary,
  toIssueSummary,
  toInvoiceSummary,
  toInvoiceItemSummary,
} from "../interfaces/contracts/workspace-flow.contract";

// ── CRUD / command DTOs ───────────────────────────────────────────────────────

export type { CreateTaskDto } from "../application/dto/create-task.dto";
export type { UpdateTaskDto } from "../application/dto/update-task.dto";

export type { OpenIssueDto } from "../application/dto/open-issue.dto";
export type { ResolveIssueDto } from "../application/dto/resolve-issue.dto";

export type { AddInvoiceItemDto } from "../application/dto/add-invoice-item.dto";
export type { UpdateInvoiceItemDto } from "../application/dto/update-invoice-item.dto";
export type { RemoveInvoiceItemDto } from "../application/dto/remove-invoice-item.dto";

// ── Query / pagination DTOs ───────────────────────────────────────────────────

export type { TaskQueryDto } from "../application/dto/task-query.dto";
export type { IssueQueryDto } from "../application/dto/issue-query.dto";
